# Categories for UI grouping
CMD_CATEGORIES = {
    'data'      : {"name": "البيانات", "icon": "📊", "color": "#4CAF50"},
    'social'    : {"name": "وسائل التواصل", "icon": "💬", "color": "#25D366"},
    'control'   : {"name": "التحكم", "icon": "🎮", "color": "#2196F3"},
    'apps'      : {"name": "التطبيقات", "icon": "📱", "color": "#FF9800"},
    'files'     : {"name": "الملفات", "icon": "📂", "color": "#9C27B0"},
    'security'  : {"name": "الأمان", "icon": "🔒", "color": "#F44336"},
    'monitor'   : {"name": "المراقبة", "icon": "🔍", "color": "#00BCD4"},
    'streaming' : {"name": "البث المباشر", "icon": "📡", "color": "#E91E63"},
    'device'    : {"name": "معلومات الجهاز", "icon": "💻", "color": "#607D8B"},
    'input'     : {"name": "الإدخال", "icon": "⌨️", "color": "#795548"},
}

def get_command(key: str) -> dict:
    """Get command definition by registry key."""
    return COMMAND_REGISTRY.get(key)

def get_commands_by_category(category: str) -> dict:
    """Get all commands in a category."""
    return {k: v for k, v in COMMAND_REGISTRY.items() if v.get('category') == category}

def get_all_categories() -> dict:
    """Get all categories with their commands."""
    result = {}
    for cat_id, cat_info in CMD_CATEGORIES.items():
        cmds = get_commands_by_category(cat_id)
        if cmds:
            result[cat_id] = {**cat_info, "commands": cmds}
    return result
